"use client";
import Link from "next/link";
import {
  Crown,
  ArrowRight,
  Sparkles,
  Zap,
  Brain,
  Layers,
  Newspaper,
  Target,
  Megaphone,
  Star,
  Globe,
  Quote,
  ChevronRight,
  Activity,
} from "lucide-react";
import { useFetch } from "@/components/useFetch";

const SERVICES = [
  {
    title: "Strategy",
    desc: "Positioning, story, pricing. Kotler-grade STP + Godin's tribe.",
    icon: Target,
    color: "#1e40af",
  },
  {
    title: "Brand",
    desc: "Voice scoring, persona fit, smallest-true-thing binding.",
    icon: Sparkles,
    color: "var(--accent)",
  },
  {
    title: "Content",
    desc: "Studio Pro visual canvas, copy generator, 7 frameworks.",
    icon: Layers,
    color: "#dc2626",
  },
  {
    title: "Growth",
    desc: "CRM + intelligence, today's moves, A/B decision engine.",
    icon: Activity,
    color: "#16a34a",
  },
  {
    title: "PR & Earned",
    desc: "PR Brain agent. News hooks, journalist angles, why-now.",
    icon: Megaphone,
    color: "#ea580c",
  },
  {
    title: "Sovereign Stack",
    desc: "Web + Desktop + Android. Your data, your machine, your call.",
    icon: Globe,
    color: "#0891b2",
  },
];

const STATS = [
  { v: "60+", l: "DB tables" },
  { v: "120+", l: "API routes" },
  { v: "44+", l: "Pages" },
  { v: "11", l: "Nova formulas" },
  { v: "7", l: "Copy frameworks" },
  { v: "6", l: "Strategy agents" },
  { v: "3", l: "Surfaces (web/desktop/Android)" },
  { v: "1", l: "Sovereign operator" },
];

export default function AgencyPage() {
  const { data: testimonials } = useFetch<any[]>("/api/testimonials");
  const { data: stories } = useFetch<any[]>("/api/brand-stories");
  const { data: settings } = useFetch<Record<string, unknown>>("/api/settings/story");

  const primaryStory = stories?.find((s: Record<string, unknown>) => s.is_primary) || stories?.[0];
  const smallestTruth = settings?.smallest_true_thing;
  const topTestimonials = (testimonials || []).slice(0, 3);

  return (
    <div className="space-y-8">
      {/* HERO */}
      <section
        className="relative overflow-hidden rounded-2xl"
        style={{
          background: "radial-gradient(circle at 20% 20%, #0f172a 0%, #1e1b4b 60%, var(--accent) 100%)",
        }}
      >
        <div
          className="absolute inset-0 opacity-10"
          style={{
            backgroundImage:
              "radial-gradient(circle at 80% 80%, rgba(255,255,255,0.4) 1px, transparent 1px)",
            backgroundSize: "20px 20px",
          }}
        />
        <div className="relative p-10 md:p-20 text-center">
          <div
            className="inline-flex items-center gap-2 mb-6 px-4 py-1.5 rounded-full"
            style={{ background: "rgba(255,255,255,0.08)", backdropFilter: "blur(8px)" }}
          >
            <Crown className="w-4 h-4 text-amber-300" />
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-amber-300">
              BAZ Empire Agency
            </span>
          </div>
          <h1 className="text-4xl md:text-7xl font-black text-white leading-[0.95] tracking-tight">
            We make brands
            <br />
            <span className="bg-gradient-to-r from-amber-300 via-rose-300 to-violet-300 bg-clip-text text-transparent">
              unignorable.
            </span>
          </h1>
          {smallestTruth && (
            <p className="text-lg md:text-xl text-slate-200 mt-6 max-w-3xl mx-auto italic">
              "{smallestTruth}"
            </p>
          )}
          <p className="text-base text-slate-300 mt-4 max-w-2xl mx-auto">
            Full-service marketing — strategy, brand, content, growth, PR — backed by a sovereign AI
            stack. Built for marketers who want leverage, not more tools.
          </p>
          <div className="flex items-center justify-center gap-3 mt-8 flex-wrap">
            <Link href="/empire" className="btn btn-primary">
              <Zap className="w-4 h-4" /> See the empire
            </Link>
            <Link
              href="#contact"
              className="btn"
              style={{
                background: "rgba(255,255,255,0.1)",
                color: "#fff",
                backdropFilter: "blur(8px)",
              }}
            >
              Start a project <ArrowRight className="w-4 h-4" />
            </Link>
          </div>
        </div>
      </section>

      {/* STATS */}
      <section className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-8 gap-2">
        {STATS.map((s) => (
          <div key={s.l} className="card p-4 text-center">
            <div className="text-xl md:text-2xl font-black bg-gradient-to-br from-violet-600 to-rose-600 bg-clip-text text-transparent">
              {s.v}
            </div>
            <div className="text-[10px] muted mt-0.5">{s.l}</div>
          </div>
        ))}
      </section>

      {/* SERVICES */}
      <section id="services">
        <div className="flex items-center gap-3 mb-3">
          <div className="w-1.5 h-7 rounded-full bg-gradient-to-b from-violet-500 to-rose-500" />
          <h2 className="text-2xl font-bold">What we do</h2>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {SERVICES.map((s) => {
            const Icon = s.icon;
            return (
              <div key={s.title} className="card card-pad card-lift group hover:shadow-lg transition-shadow">
                <div
                  className="w-10 h-10 rounded-lg grid place-items-center"
                  style={{ background: `${s.color}15`, color: s.color }}
                >
                  <Icon className="w-5 h-5" />
                </div>
                <div className="font-bold text-lg mt-3">{s.title}</div>
                <div className="text-sm muted mt-1">{s.desc}</div>
              </div>
            );
          })}
        </div>
      </section>

      {/* SMALLEST TRUE THING / STORY */}
      {primaryStory && (
        <section
          className="card card-pad card-lift card-lift"
          style={{
            background: "linear-gradient(135deg, rgba(220,38,38,0.05), rgba(245,158,11,0.04))",
          }}
        >
          <div className="flex items-start gap-3">
            <Quote className="w-6 h-6 text-red-500 flex-shrink-0 mt-1" />
            <div>
              <div className="text-xs uppercase tracking-wider text-red-700 font-bold mb-1">
                The story we tell
              </div>
              <h3 className="text-2xl font-bold mb-2">{primaryStory.title}</h3>
              <p className="text-base text-slate-700 dark:text-zinc-300 mb-2">
                <strong>Hook:</strong> {primaryStory.hook}
              </p>
              {primaryStory.problem && (
                <p className="text-sm text-slate-600 dark:text-zinc-300 mb-1">
                  <strong>Problem:</strong> {primaryStory.problem}
                </p>
              )}
              {primaryStory.shift && (
                <p className="text-sm text-slate-600 dark:text-zinc-300 mb-1">
                  <strong>Shift:</strong> {primaryStory.shift}
                </p>
              )}
              {primaryStory.resolution && (
                <p className="text-sm text-slate-600 dark:text-zinc-300 mb-1">
                  <strong>Resolution:</strong> {primaryStory.resolution}
                </p>
              )}
            </div>
          </div>
        </section>
      )}

      {/* TESTIMONIALS */}
      {topTestimonials.length > 0 && (
        <section>
          <div className="flex items-center gap-3 mb-3">
            <div className="w-1.5 h-7 rounded-full bg-amber-500" />
            <h2 className="text-2xl font-bold">What clients say</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {topTestimonials.map((t: Record<string, unknown>) => (
              <div key={t.id} className="card card-pad card-lift card-lift">
                <div className="flex items-center gap-1 mb-2">
                  {Array.from({ length: t.rating || 5 }).map((_, i) => (
                    <Star key={i} className="w-4 h-4 fill-amber-400 text-amber-400" />
                  ))}
                </div>
                <p className="text-sm text-slate-700 dark:text-zinc-300 italic">
                  "{t.quote || t.text || t.body}"
                </p>
                <div className="mt-3 text-xs">
                  <div className="font-semibold">{t.author || t.name || "Client"}</div>
                  {(t.role || t.company) && (
                    <div className="muted">
                      {t.role}
                      {t.role && t.company ? " · " : ""}
                      {t.company}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* CONTACT */}
      <section
        id="contact"
        className="card card-pad card-lift text-center"
        style={{
          background: "linear-gradient(135deg, rgba(var(--theme-brand-rgb), 0.06), rgba(220,38,38,0.04))",
        }}
      >
        <h2 className="text-2xl font-bold">Start a project</h2>
        <p className="text-sm muted mt-2 max-w-xl mx-auto">
          We take on 3-5 new clients per quarter. If your brand is ready to be unignorable, let's
          talk.
        </p>
        <div className="mt-4 flex items-center justify-center gap-3">
          <Link href="/intelligence" className="btn btn-primary">
            See intelligence <ArrowRight className="w-4 h-4" />
          </Link>
          <Link href="/empire" className="btn btn-secondary">
            Explore the platform
          </Link>
        </div>
      </section>
    </div>
  );
}
