];

const CATEGORY_FALLBACK: Record<string, string> = {
  "Social Media Marketing": "/social",
  "Content Marketing": "/content",
  "Lifecycle Email Marketing": "/emails",
  "Cold Email Marketing": "/sequences",
  "User Research": "/personas",
  "Influencer Marketing": "/influencer",
  "Market Research": "/competitive-intelligence",
  "Marketing for Product Hunt Launch": "/launch",
};

export function mapToolToHub(title: string, category: string): { hubPath?: string; hubLabel?: string } {
  const lower = title.toLowerCase();
  for (const m of MAPPINGS) {
    if (m.match.some((kw) => lower.includes(kw))) {
      return { hubPath: m.hubPath, hubLabel: m.hubLabel };
    }
  }
  const fallback = CATEGORY_FALLBACK[category];
  if (fallback) return { hubPath: fallback, hubLabel: undefined };
  return {};
