"use client";
import Link from "next/link";
import { useMemo, useState } from "react";
import {
  Smartphone,
  Palette,
  FileText,
  PenTool,
  MonitorSmartphone,
  MessageSquare,
  ShoppingCart,
  CalendarDays,
  LayoutGrid,
  Magnet,
  UserCheck,
  Globe,
  Megaphone,
  Sparkles,
  Radio,
  MousePointerClick,
  TrendingUp,
  Newspaper,
  Share2,
  Search,
  Target,
  Briefcase,
  Video,
  Speakerphone,
  ArrowUpRight,
  type LucideIcon,
} from "lucide-react";
import { AGENCY_TYPES, HUB_INDEX, AGENCY_TYPE_COUNT } from "@/lib/agencyTypes";

const ICONS: Record<string, LucideIcon> = {
  Smartphone,
  Palette,
  FileText,
  PenTool,
  MonitorSmartphone,
  MessageSquare,
  ShoppingCart,
  CalendarDays,
  LayoutGrid,
  Magnet,
  UserCheck,
  Globe,
  Megaphone,
  Sparkles,
  Radio,
  MousePointerClick,
  TrendingUp,
  Newspaper,
  Share2,
  Search,
  Target,
  Briefcase,
  Video,
  Speakerphone,
};

export default function AgencyDirectoryPage() {
  const [query, setQuery] = useState("");

  const uniqueHubSections = useMemo(() => {
    const set = new Set<string>();
    for (const t of AGENCY_TYPES) t.hubPaths.forEach((p) => set.add(p));
    return set.size;
  }, []);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return AGENCY_TYPES;
    return AGENCY_TYPES.filter(
      (t) =>
        t.label.toLowerCase().includes(q) ||
        t.description.toLowerCase().includes(q) ||
        t.hubPaths.some((p) => (HUB_INDEX[p] || "").toLowerCase().includes(q)),
    );
  }, [query]);

  return (
    <div className="space-y-8">
      {/* HERO */}
      <section
        className="relative overflow-hidden rounded-2xl"
        style={{
          background: "radial-gradient(circle at 18% 18%, #1e1b4b 0%, #0f172a 55%, var(--accent) 120%)",
        }}
      >
        <div
          className="absolute inset-0 opacity-10"
          style={{
            backgroundImage:
              "radial-gradient(circle at 82% 80%, rgba(255,255,255,0.45) 1px, transparent 1px)",
            backgroundSize: "22px 22px",
          }}
        />
        <div className="relative p-8 md:p-14">
          <div
            className="inline-flex items-center gap-2 mb-4 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase tracking-[0.2em]"
            style={{ background: "rgba(255,255,255,0.08)", backdropFilter: "blur(8px)", color: "#fcd34d" }}
          >
            Agency Directory
          </div>
          <h1 className="text-3xl md:text-5xl font-black text-white leading-[0.98] tracking-tight">
            The Marketing Hub is
            <br />
            <span className="bg-gradient-to-r from-amber-300 via-rose-300 to-violet-300 bg-clip-text text-transparent">
              every agency type.
            </span>
          </h1>
          <p className="text-base text-slate-300 mt-4 max-w-2xl">
            One platform that replaces {AGENCY_TYPE_COUNT} external agency disciplines. Browse the
            taxonomy and see exactly which native hub sections deliver each one.
          </p>
          <div className="flex flex-wrap gap-2 mt-6">
            <div className="card px-4 py-2 text-center" style={{ background: "rgba(255,255,255,0.06)" }}>
              <div className="text-xl font-black text-white">{AGENCY_TYPE_COUNT}</div>
              <div className="text-[10px] text-slate-300">Agency types</div>
            </div>
            <div className="card px-4 py-2 text-center" style={{ background: "rgba(255,255,255,0.06)" }}>
              <div className="text-xl font-black text-white">{uniqueHubSections}</div>
              <div className="text-[10px] text-slate-300">Hub sections mapped</div>
            </div>
            <div className="card px-4 py-2 text-center" style={{ background: "rgba(255,255,255,0.06)" }}>
              <div className="text-xl font-black text-white">1</div>
              <div className="text-[10px] text-slate-300">Sovereign platform</div>
            </div>
          </div>
        </div>
      </section>

      {/* SEARCH */}
      <div className="flex items-center gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 muted" />
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search agency types or hub capabilities…"
            className="input w-full pl-9"
          />
        </div>
        <div className="text-sm muted whitespace-nowrap">
          {filtered.length} / {AGENCY_TYPE_COUNT}
        </div>
      </div>

      {/* GRID */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filtered.map((t) => {
          const Icon = ICONS[t.icon] || Target;
          return (
            <div
              key={t.slug}
              className="card card-pad card-lift group hover:shadow-lg transition-shadow flex flex-col"
            >
              <div className="flex items-start gap-3">
                <div
                  className="w-11 h-11 rounded-xl grid place-items-center flex-shrink-0"
                  style={{ background: `${t.color}15`, color: t.color }}
                >
                  <Icon className="w-5 h-5" />
                </div>
                <div className="min-w-0">
                  <h3 className="font-bold text-lg leading-tight">{t.label}</h3>
                  <p className="text-sm muted mt-1">{t.description}</p>
                </div>
              </div>

              <div className="mt-4 pt-3 border-t border-black/5 dark:border-white/10">
                <div className="text-[10px] uppercase tracking-wider muted mb-2">
                  Delivered by {t.hubPaths.length} hub sections
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {t.hubPaths.map((p) => (
                    <Link
                      key={p}
                      href={p}
                      className="inline-flex items-center gap-0.5 text-[11px] font-medium px-2 py-1 rounded-md transition-colors"
                      style={{ background: `${t.color}12`, color: t.color }}
                    >
                      {HUB_INDEX[p] || p}
                      <ArrowUpRight className="w-3 h-3 opacity-60" />
                    </Link>
                  ))}
                </div>
              </div>
            </div>
          );
        })}
      </section>

      {filtered.length === 0 && (
        <div className="card card-pad text-center muted">No agency types match “{query}”.</div>
      )}

      {/* SOURCE */}
      <p className="text-xs muted text-center">
        Agency-type taxonomy sourced from cmmodels.com · Mapped to native Marketing Hub sections.
      </p>
    </div>
  );
}

