/** Update a row for a surface (partial fields). */
export function updateSeed(
  slug: string,
  id: string,
  input: { title?: string; status?: string; category?: string; body?: string; url?: string; meta?: Record<string, unknown> },
): boolean {
  const table = TABLE(slug);
  const existing = db.prepare(`SELECT * FROM ${table} WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
  if (!existing) return false;
  const next = {
    title: input.title ?? String(existing.title),
    status: input.status ?? String(existing.status),
    category: input.category ?? String(existing.category),
    body: input.body ?? String(existing.body || ""),
    url: input.url ?? String(existing.url || ""),
    meta: input.meta !== undefined ? JSON.stringify(input.meta) : String(existing.meta || "{}"),
  };
  db.prepare(
    `UPDATE ${table} SET title = ?, status = ?, category = ?, body = ?, url = ?, meta = ?, updated_at = ? WHERE id = ?`,
  ).run(next.title, next.status, next.category, next.body, next.url, next.meta, now(), id);
  return true;
}

/** Delete a row for a surface. */
export function deleteSeed(slug: string, id: string): boolean {
  const table = TABLE(slug);
  const res = db.prepare(`DELETE FROM ${table} WHERE id = ?`).run(id);
  return res.changes > 0;
}

