"use client";

import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { Plus, X, Pencil, Trash2 } from "lucide-react";

type Row = {
  id: string;
  title: string;
  status: string;
  category: string;
  body: string;
  url: string;
  meta: Record<string, unknown>;
  created_at: number;
};

const STATUS_COLOR: Record<string, string> = {
  draft: "#94a3b8", planning: "#0ea5e9", active: "#22c55e", live: "#22c55e", published: "#22c55e",
  recording: "#f59e0b", filming: "#f59e0b", editing: "#f59e0b", scripting: "#0ea5e9", sending: "#f59e0b",
  pitching: "#0ea5e9", applied: "#0ea5e9", identified: "#0ea5e9", nurturing: "#f59e0b", testing: "#f59e0b",
  design: "#6366f1", development: "#8b5cf6", qa: "#f59e0b", maintenance: "#64748b", discovery: "#0ea5e9",
  concept: "#8b5cf6", refinement: "#f59e0b", approved: "#22c55e", "rolled-out": "#22c55e", assigned: "#0ea5e9",
  review: "#f59e0b", repurposed: "#64748b", wireframe: "#6366f1", mockup: "#8b5cf6", prototype: "#f59e0b",
  handoff: "#0ea5e9", strategy: "#6366f1", launch: "#22c55e", optimizing: "#f59e0b", scaling: "#22c55e", maint: "#64748b",
  "list-build": "#0ea5e9", scripting: "#6366f1", replied: "#22c55e", converted: "#22c55e", nurture: "#f59e0b",
  audit: "#0ea5e9", build: "#6366f1", migrate: "#8b5cf6", optimize: "#f59e0b", scale: "#22c55e",
  idea: "#0ea5e9", planning: "#6366f1", confirmed: "#22c55e", wrap: "#64748b", recap: "#64748b",
  kickoff: "#0ea5e9", production: "#6366f1", report: "#64748b", brief: "#0ea5e9", research: "#6366f1",
  analysis: "#6366f1", framework: "#8b5cf6", workshop: "#f59e0b", roadmap: "#0ea5e9", adoption: "#22c55e",
  diagnose: "#0ea5e9", hypothesis: "#6366f1", analyze: "#8b5cf6", recommend: "#f59e0b", implement: "#0ea5e9", measure: "#22c55e",
  treatment: "#8b5cf6", shoot: "#6366f1", grade: "#f59e0b", deliver: "#22c55e", calendar: "#0ea5e9", create: "#6366f1",
  schedule: "#0ea5e9", engage: "#f59e0b", pitch: "#0ea5e9", secured: "#22c55e", measuring: "#64748b",
  keywords: "#0ea5e9", onpage: "#6366f1", content: "#8b5cf6", links: "#f59e0b", setup: "#6366f1", test: "#f59e0b",
  "media-buy": "#f59e0b", produce: "#6366f1", scout: "#0ea5e9", outreach: "#6366f1", negotiate: "#f59e0b",
  active: "#22c55e", delivered: "#22c55e", paid: "#22c55e", buy: "#f59e0b", plan: "#6366f1",
  "list-build": "#0ea5e9", "rolled-out": "#22c55e", storyboard: "#8b5cf6",
};

const emptyForm = { id: "", title: "", status: "draft", category: "general", body: "", url: "" };

export function SeedSurface({ slug, label, icon }: { slug: string; label: string; icon: React.ReactNode }) {
  const { data, loading, error, reload } = useFetch<{ items: Row[]; config: { statuses: string[]; categories: string[]; label: string } }>(`/api/seed/${slug}`);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);

  const openNew = () => {
    setEditingId(null);
    const first = data?.config.statuses?.[0] || "draft";
    const firstCat = data?.config.categories?.[0] || "general";
    setForm({ ...emptyForm, status: first, category: firstCat });
    setShowForm(true);
  };

  const openEdit = (it: Row) => {
    setEditingId(it.id);
    setForm({ id: it.id, title: it.title, status: it.status, category: it.category, body: it.body, url: it.url });
    setShowForm(true);
  };

  const save = async () => {
    if (!form.title) return;
    setSaving(true);
    try {
      if (editingId) {
        await fetch(`/api/seed/${slug}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(form),
        });
      } else {
        await fetch(`/api/seed/${slug}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(form),
        });
      }
      setForm(emptyForm);
      setEditingId(null);
      setShowForm(false);
      reload();
    } finally {
      setSaving(false);
    }
  };

  const remove = async (id: string) => {
    if (!confirm("Delete this item?")) return;
    await fetch(`/api/seed/${slug}?id=${encodeURIComponent(id)}`, { method: "DELETE" });
    reload();
  };

  const statuses = data?.config.statuses || [];
  const categories = data?.config.categories || [];

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              {icon} {label}
            </h1>
            <p className="mt-1 text-gray-600">
              Manage your {label.toLowerCase()} pipeline.
              <span className="ml-2 inline-flex items-center gap-1 text-xs font-medium text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full border border-amber-200">
                Manual log — ingest adapter pending
              </span>
            </p>
          </div>
          <button onClick={openNew} className="flex items-center gap-1.5 bg-indigo-600 text-white text-sm font-semibold px-4 py-2 rounded-lg hover:bg-indigo-700">
            <Plus className="w-4 h-4" /> New
          </button>
        </div>

        {showForm && (
          <div className="bg-white border rounded-xl p-5 shadow-sm space-y-3">
            <div className="flex items-center justify-between">
              <div className="text-sm font-semibold text-gray-700">{editingId ? "Edit item" : "New item"}</div>
              <button onClick={() => { setShowForm(false); setEditingId(null); setForm(emptyForm); }} className="text-gray-400 hover:text-gray-600">
                <X className="w-4 h-4" />
              </button>
            </div>
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="Title" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
            <div className="grid grid-cols-2 gap-3">
              <select className="border rounded-lg px-3 py-2 text-sm" value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })}>
                {statuses.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
              <select className="border rounded-lg px-3 py-2 text-sm" value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })}>
                {categories.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="URL (optional)" value={form.url} onChange={(e) => setForm({ ...form, url: e.target.value })} />
            <textarea className="w-full border rounded-lg px-3 py-2 text-sm" rows={3} placeholder="Notes / body" value={form.body} onChange={(e) => setForm({ ...form, body: e.target.value })} />
            <button onClick={save} disabled={saving || !form.title} className="bg-indigo-600 text-white text-sm font-semibold px-4 py-2 rounded-lg disabled:opacity-50">
              {saving ? "Saving…" : editingId ? "Save changes" : "Save"}
            </button>
          </div>
        )}

        {loading && <div className="text-sm text-slate-500">Loading…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {data.items.map((it) => (
              <div key={it.id} className="bg-white border rounded-xl p-4 shadow-sm flex flex-col">
                <div className="flex items-start justify-between gap-2 mb-2">
                  <div className="font-bold text-sm text-gray-900 line-clamp-2">{it.title}</div>
                  <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded text-white shrink-0" style={{ background: STATUS_COLOR[it.status] || "#94a3b8" }}>{it.status}</span>
                </div>
                <div className="text-xs text-indigo-500 mb-2 capitalize">{it.category}</div>
                {it.body && <p className="text-xs text-slate-600 line-clamp-3">{it.body}</p>}
                {it.url && <a href={it.url} target="_blank" rel="noreferrer" className="text-xs text-indigo-600 hover:underline mt-2 inline-block">Link →</a>}
                <div className="flex items-center gap-2 mt-3 pt-3 border-t border-gray-100">
                  <button onClick={() => openEdit(it)} className="inline-flex items-center gap-1 text-xs text-slate-500 hover:text-indigo-600">
                    <Pencil className="w-3.5 h-3.5" /> Edit
                  </button>
                  <button onClick={() => remove(it.id)} className="inline-flex items-center gap-1 text-xs text-slate-500 hover:text-rose-600">
                    <Trash2 className="w-3.5 h-3.5" /> Delete
                  </button>
                </div>
              </div>
            ))}
            {data.items.length === 0 && <div className="col-span-full text-center text-slate-400 py-12">No items yet. Create one above.</div>}
          </div>
        )}
      </div>
    </div>
  );
}

