import { notFound } from "next/navigation";
import {
  Smartphone, Palette, FileText, PenTool, MonitorSmartphone, MessageSquare,
  ShoppingCart, CalendarDays, LayoutGrid, Magnet, UserCheck, Globe, Megaphone,
  Sparkles, Radio, MousePointerClick, TrendingUp, Newspaper, Share2, Search,
  Target, Briefcase, Video, Volume2, type LucideIcon,
} from "lucide-react";
import { SeedSurface } from "@/components/seed-surface/SeedSurface";
import { AGENCY_TYPES } from "@/lib/agencyTypes";

export const dynamic = "force-dynamic";

const ICONS: Record<string, LucideIcon> = {
  Smartphone, Palette, FileText, PenTool, MonitorSmartphone, MessageSquare,
  ShoppingCart, CalendarDays, LayoutGrid, Magnet, UserCheck, Globe, Megaphone,
  Sparkles, Radio, MousePointerClick, TrendingUp, Newspaper, Share2, Search,
  Target, Briefcase, Video, Volume2,
};

export function generateStaticParams() {
  return AGENCY_TYPES.map((t) => ({ slug: t.slug }));
}

export default function AgencyModulePage({ params }: { params: { slug: string } }) {
  const type = AGENCY_TYPES.find((t) => t.slug === params.slug);
  if (!type) notFound();
  const Icon = ICONS[type.icon] || Target;
  return (
    <SeedSurface slug={type.slug} label={type.label} icon={<Icon className="w-7 h-7 text-indigo-600" />} />
  );
}

