export const AGENCY_FIELD_SCHEMA: Record<string, AgencySchema> = Object.fromEntries(
  AGENCY_SURFACES.map((s) => [
    s.slug,
    {
      stages: s.statuses,
      categories: s.categories,
      fields: [...(FIELDS[s.slug] || []), ...BASE_FIELDS],
      kpis: KPIS[s.slug] || [],
    } as AgencySchema,
  ]),
);

export function getAgencySchema(slug: string): AgencySchema | undefined {
  return AGENCY_FIELD_SCHEMA[slug];
}

/**
 * Unified agency data layer.
 *
 * Replaces the 24 independent `seed_<slug>` tables with ONE polymorphic
 * `agency_items` table + a `agency_clients` table (distinct from the CRM
 * `clients` table). All 24 agency modules read/write through here, scoped by
 * workspace. The first call backfills existing seed-surface rows so no data is
 * lost (idempotent — preserves original ids/created_at).
 */
import { db, now, uid } from "@/lib/db";
import { AGENCY_SURFACES } from "./agency-surfaces";
import { getAgencySchema } from "./agencySchema";

export interface AgencyItem {
  id: string;
  workspace_id: string;
  agency_type: string;
  client_id: string | null;
  status: string;
  category: string;
  title: string;
  body: string;
  url: string;
  field_values: Record<string, unknown>;
  meta: Record<string, unknown>;
  created_by: string | null;
  created_at: number;
  updated_at: number;
}

export interface AgencyClient {
  id: string;
  workspace_id: string;
  name: string;
  slug: string;
  status: string;
  theme: Record<string, unknown>;
  stripe_customer_id: string | null;
  created_at: number;
  updated_at: number;
}

const TABLE = (slug: string) => `seed_${slug.replace(/[^a-z0-9]/gi, "_").toLowerCase()}`;
let ensured = false;
let backfilled = false;

export function ensureAgencyTables(): void {
  if (ensured) return;
  db.exec(`
    CREATE TABLE IF NOT EXISTS agency_items (
      id TEXT PRIMARY KEY,
      workspace_id TEXT NOT NULL DEFAULT 'default',
      agency_type TEXT NOT NULL,
      client_id TEXT,
      status TEXT NOT NULL DEFAULT 'draft',
      category TEXT NOT NULL DEFAULT 'general',
      title TEXT NOT NULL,
      body TEXT NOT NULL DEFAULT '',
      url TEXT NOT NULL DEFAULT '',
      field_values TEXT NOT NULL DEFAULT '{}',
      meta TEXT NOT NULL DEFAULT '{}',
      created_by TEXT,
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_agency_items_ws_type ON agency_items(workspace_id, agency_type);
    CREATE INDEX IF NOT EXISTS idx_agency_items_client ON agency_items(client_id);
    CREATE INDEX IF NOT EXISTS idx_agency_items_type ON agency_items(agency_type);

    CREATE TABLE IF NOT EXISTS agency_clients (
      id TEXT PRIMARY KEY,
      workspace_id TEXT NOT NULL DEFAULT 'default',
      name TEXT NOT NULL,
      slug TEXT NOT NULL,
      status TEXT NOT NULL DEFAULT 'active',
      theme TEXT NOT NULL DEFAULT '{}',
      stripe_customer_id TEXT,
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_agency_clients_ws ON agency_clients(workspace_id);
  `);
  ensured = true;
  // Backfill once, lazily, if the unified table is empty.
  const count = (db.prepare(`SELECT COUNT(*) c FROM agency_items`).get() as { c: number }).c;
  if (count === 0) backfillFromSeedSurfaces();
}

/** Migrate rows from each `seed_<slug>` table into the unified `agency_items`. */
export function backfillFromSeedSurfaces(): void {
  if (backfilled) return;
  ensureAgencyTables();
  const t = now();
  const insert = db.prepare(
    `INSERT OR IGNORE INTO agency_items
      (id, workspace_id, agency_type, status, category, title, body, url, field_values, meta, created_by, created_at, updated_at)
     VALUES (?, 'default', ?, ?, ?, ?, ?, ?, ?, '{}', NULL, ?, ?)`,
  );
  for (const s of AGENCY_SURFACES) {
    const table = TABLE(s.slug);
    let rows: Record<string, unknown>[] = [];
    try {
      rows = db.prepare(`SELECT * FROM ${table}`).all() as Record<string, unknown>[];
    } catch {
      continue; // table doesn't exist yet — skip
    }
    for (const r of rows) {
      let fv: Record<string, unknown> = {};
      try {
        fv = JSON.parse(String(r.meta || "{}"));
      } catch {
        fv = {};
      }
      const created = Number(r.created_at) || t;
      insert.run(
        String(r.id),
        s.slug,
        String(r.status || "draft"),
        String(r.category || "general"),
        String(r.title || ""),
        String(r.body || ""),
        String(r.url || ""),
        JSON.stringify(fv),
        created,
        created,
      );
    }
  }
  backfilled = true;
}

function parseRow(r: Record<string, unknown>): AgencyItem {
  let fv: Record<string, unknown> = {};
  try {
    fv = JSON.parse(String(r.field_values || "{}"));
  } catch {
    fv = {};
  }
  let meta: Record<string, unknown> = {};
  try {
    meta = JSON.parse(String(r.meta || "{}"));
  } catch {
    meta = {};
  }
  return {
    id: String(r.id),
    workspace_id: String(r.workspace_id),
    agency_type: String(r.agency_type),
    client_id: r.client_id ? String(r.client_id) : null,
    status: String(r.status),
    category: String(r.category),
    title: String(r.title),
    body: String(r.body || ""),
    url: String(r.url || ""),
    field_values: fv,
    meta,
    created_by: r.created_by ? String(r.created_by) : null,
    created_at: Number(r.created_at) || 0,
    updated_at: Number(r.updated_at) || 0,
  };
}

export interface ListAgencyOpts {
  workspaceId?: string;
  clientId?: string;
  status?: string;
  category?: string;
  limit?: number;
}

export function listAgencyItems(type: string, opts: ListAgencyOpts = {}): AgencyItem[] {
  ensureAgencyTables();
  const where: string[] = ["agency_type = ?"];
  const params: unknown[] = [type];
