+function parseRow(r: Record<string, unknown>): AgencyItem {
+  let fv: Record<string, unknown> = {};
+  try {
+    fv = JSON.parse(String(r.field_values || "{}"));
+  } catch {
+    fv = {};
+  }
+  let meta: Record<string, unknown> = {};
+  try {
+    meta = JSON.parse(String(r.meta || "{}"));
+  } catch {
+    meta = {};
+  }
+  return {
+    id: String(r.id),
+    workspace_id: String(r.workspace_id),
+    agency_type: String(r.agency_type),
+    client_id: r.client_id ? String(r.client_id) : null,
+    status: String(r.status),
+    category: String(r.category),
+    title: String(r.title),
+    body: String(r.body || ""),
+    url: String(r.url || ""),
+    field_values: fv,
+    meta,
+    created_by: r.created_by ? String(r.created_by) : null,
+    created_at: Number(r.created_at) || 0,
+    updated_at: Number(r.updated_at) || 0,
+  };
+}
+
+export interface ListAgencyOpts {
+  workspaceId?: string;
+  clientId?: string;
+  status?: string;
+  category?: string;
+  limit?: number;
+}
+
+export function listAgencyItems(type: string, opts: ListAgencyOpts = {}): AgencyItem[] {
+  ensureAgencyTables();
+  const where: string[] = ["agency_type = ?"];
+  const params: unknown[] = [type];
+  if (opts.workspaceId) {
+    where.push("workspace_id = ?");
+    params.push(opts.workspaceId);
+  }
+  if (opts.clientId) {
+    where.push("client_id = ?");
+    params.push(opts.clientId);
+  }
+  if (opts.status) {
+    where.push("status = ?");
+    params.push(opts.status);
+  }
+  if (opts.category) {
+    where.push("category = ?");
+    params.push(opts.category);
+  }
+  const limit = opts.limit ?? 200;
+  const rows = db
+    .prepare(`SELECT * FROM agency_items WHERE ${where.join(" AND ")} ORDER BY updated_at DESC LIMIT ?`)
+    .all(...params, limit) as Record<string, unknown>[];
+  return rows.map(parseRow);
+}
+
+export function getAgencyItem(id: string): AgencyItem | null {
+  ensureAgencyTables();
+  const r = db.prepare(`SELECT * FROM agency_items WHERE id = ?`).get(id) as Record<string, unknown> | undefined;
+  return r ? parseRow(r) : null;
+}
+
+export function createAgencyItem(
+  type: string,
+  input: {
+    workspaceId: string;
+    title: string;
+    status?: string;
+    category?: string;
+    body?: string;
+    url?: string;
+    client_id?: string | null;
+    field_values?: Record<string, unknown>;
+    created_by?: string | null;
+  },
+): string {
+  ensureAgencyTables();
+  const id = uid(type);
+  const t = now();
+  db.prepare(
+    `INSERT INTO agency_items
+      (id, workspace_id, agency_type, client_id, status, category, title, body, url, field_values, meta, created_by, created_at, updated_at)
+     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, '{}', ?, ?, ?)`,
+  ).run(
+    id,
+    input.workspaceId,
+    type,
+    input.client_id ?? null,
+    input.status || "draft",
+    input.category || "general",
+    input.title,
+    input.body || "",
+    input.url || "",
+    JSON.stringify(input.field_values || {}),
+    input.created_by ?? null,
+    t,
+    t,
+  );
+  return id;
+}
+
+export function updateAgencyItem(
+  id: string,
+  input: {
+    title?: string;
+    status?: string;
+    category?: string;
+    body?: string;
+    url?: string;
+    client_id?: string | null;
+    field_values?: Record<string, unknown>;
+  },
+): boolean {
+  ensureAgencyTables();
+  const r = db.prepare(`SELECT id FROM agency_items WHERE id = ?`).get(id);
+  if (!r) return false;
+  const sets: string[] = [];
+  const params: unknown[] = [];
+  if (input.title !== undefined) {
+    sets.push("title = ?");
+    params.push(input.title);
+  }
+  if (input.status !== undefined) {
+    sets.push("status = ?");
+    params.push(input.status);
+  }
+  if (input.category !== undefined) {
+    sets.push("category = ?");
+    params.push(input.category);
+  }
+  if (input.body !== undefined) {
+    sets.push("body = ?");
+    params.push(input.body);
+  }
+  if (input.url !== undefined) {
+    sets.push("url = ?");
+    params.push(input.url);
+  }
+  if (input.client_id !== undefined) {
+    sets.push("client_id = ?");
+    params.push(input.client_id);
+  }
+  if (input.field_values !== undefined) {
+    sets.push("field_values = ?");
+    params.push(JSON.stringify(input.field_values));
+  }
+  sets.push("updated_at = ?");
+  params.push(now());
+  db.prepare(`UPDATE agency_items SET ${sets.join(", ")} WHERE id = ?`).run(...params, id);
+  return true;
+}
+
+export function deleteAgencyItem(id: string): boolean {
+  ensureAgencyTables();
+  const res = db.prepare(`DELETE FROM agency_items WHERE id = ?`).run(id);
+  return res.changes > 0;
+}
+
+/** Compute a module's live KPIs from its items' structured field_values. */
+export function computeAgencyKpis(type: string, items: AgencyItem[]): { key: string; label: string; value: number; type: string }[] {
+  const schema = getAgencySchema(type);
+  if (!schema) return [];
+  return schema.kpis.map((kpi) => {
+    const values = items
+      .map((it) => Number(it.field_values?.[kpi.key]))
+      .filter((n) => Number.isFinite(n));
+    const value = values.length
+      ? kpi.aggregate === "avg"
+        ? values.reduce((a, b) => a + b, 0) / values.length
+        : values.reduce((a, b) => a + b, 0)
+      : 0;
+    return { key: kpi.key, label: kpi.label, value: Math.round(value * 100) / 100, type: kpi.type };
+  });
+}
+
+// ── Clients (agency workspace sub-entity, distinct from CRM `clients`) ──
+
+export function listAgencyClients(workspaceId: string): AgencyClient[] {
+  ensureAgencyTables();
+  const rows = db
+    .prepare(`SELECT * FROM agency_clients WHERE workspace_id = ? ORDER BY name ASC`)
+    .all(workspaceId) as Record<string, unknown>[];
+  return rows.map((r) => ({
+    id: String(r.id),
+    workspace_id: String(r.workspace_id),
+    name: String(r.name),
+    slug: String(r.slug),
+    status: String(r.status),
+    theme: (() => {
+      try {
+        return JSON.parse(String(r.theme || "{}"));
+      } catch {
+        return {};
+      }
+    })(),
+    stripe_customer_id: r.stripe_customer_id ? String(r.stripe_customer_id) : null,
+    created_at: Number(r.created_at) || 0,
+    updated_at: Number(r.updated_at) || 0,
+  }));
+}
+
+export function createAgencyClient(input: {
+  workspaceId: string;
+  name: string;
+  slug: string;
+  status?: string;
+  theme?: Record<string, unknown>;
+  stripe_customer_id?: string | null;
+}): string {
+  ensureAgencyTables();
+  const id = uid("acl_");
+  const t = now();
+  db.prepare(
+    `INSERT INTO agency_clients (id, workspace_id, name, slug, status, theme, stripe_customer_id, created_at, updated_at)
+     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
+  ).run(
+    id,
+    input.workspaceId,
+    input.name,
+    input.slug,
+    input.status || "active",
+    JSON.stringify(input.theme || {}),
+    input.stripe_customer_id ?? null,
+    t,
+    t,
+  );
+  return id;
+}

