import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { workspaceScoped } from "@/lib/rbac";
import { AGENCY_FIELD_SCHEMA } from "@/lib/agencySchema";
import {
  ensureAgencyTables,
  listAgencyItems,
  createAgencyItem,
  computeAgencyKpis,
} from "@/lib/agency-db";

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest, { params }: { params: { type: string } }) {
  try {
    const ws = workspaceScoped(req);
    const schema = AGENCY_FIELD_SCHEMA[params.type];
    if (!schema) return json({ error: "Unknown agency type" }, 404);
    ensureAgencyTables();
    const sp = req.nextUrl.searchParams;
    const items = listAgencyItems(params.type, {
      workspaceId: ws,
      clientId: sp.get("client") || undefined,
      status: sp.get("status") || undefined,
      category: sp.get("category") || undefined,
      limit: sp.get("limit") ? Number(sp.get("limit")) : 200,
    });
    const kpis = computeAgencyKpis(params.type, items);
    return json({ items, kpis, schema });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Failed" }, 500);
  }
}

export async function POST(req: NextRequest, { params }: { params: { type: string } }) {
  try {
    const ws = workspaceScoped(req);
    if (!AGENCY_FIELD_SCHEMA[params.type]) return json({ error: "Unknown agency type" }, 404);
    ensureAgencyTables();
    const body = await req.json().catch(() => null);
    if (!body?.title) return json({ error: "title is required" }, 400);
    const id = createAgencyItem(params.type, {
      workspaceId: ws,
      title: String(body.title),
      status: body.status,
      category: body.category,
      body: body.body,
      url: body.url,
      client_id: body.client_id ?? null,
      field_values: body.field_values,
      created_by: body.created_by ?? null,
    });
    return json({ id }, 201);
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Create failed" }, 500);
  }
}

