      category: body.category,
      body: body.body,
      url: body.url,
      client_id: body.client_id,
      field_values: body.field_values,
    });
    if (!ok) return json({ error: "Not found" }, 404);
    return json({ ok: true });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Update failed" }, 500);
  }
}

export async function DELETE(req: NextRequest, { params }: { params: { type: string; id: string } }) {
  try {
    workspaceScoped(req);
    ensureAgencyTables();
    const ok = deleteAgencyItem(params.id);
    if (!ok) return json({ error: "Not found" }, 404);
    return json({ ok: true });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Delete failed" }, 500);
  }
}

