import { db } from "../src/lib/db";
import { backfillFromSeedSurfaces, listAgencyItems } from "../src/lib/agency-db";
import { AGENCY_SURFACES } from "../src/lib/agency-surfaces";

console.log("🔁 Migrating seed-surface agency rows → unified agency_items table...\n");

backfillFromSeedSurfaces();

const TABLE = (slug: string) => `seed_${slug.replace(/[^a-z0-9]/gi, "_").toLowerCase()}`;
let totalSeed = 0;
let totalItems = 0;
let mismatches = 0;

for (const s of AGENCY_SURFACES) {
  let seedCount = 0;
  try {
    seedCount = (db.prepare(`SELECT COUNT(*) c FROM ${TABLE(s.slug)}`).get() as { c: number }).c;
  } catch {
    seedCount = 0;
  }
  const itemCount = listAgencyItems(s.slug, { workspaceId: "default" }).length;
  totalSeed += seedCount;
  totalItems += itemCount;
  const ok = seedCount === itemCount ? "✓" : "✗ MISMATCH";
  if (seedCount !== itemCount) mismatches++;
  console.log(`  ${ok} ${s.label.padEnd(28)} seed=${seedCount}  →  items=${itemCount}`);
}

console.log(`\n  Total: seed=${totalSeed}  items=${totalItems}`);
console.log(mismatches === 0 ? "\n✅ Parity OK — no data lost." : `\n❌ ${mismatches} type(s) mismatched.`);

