/** Migrate rows from each `seed_<slug>` table into the unified `agency_items`. */
export function backfillFromSeedSurfaces(): void {
  if (backfilled) return;
  ensureAgencyTables();
  const t = now();
  const insert = db.prepare(
    `INSERT OR IGNORE INTO agency_items
      (id, workspace_id, agency_type, status, category, title, body, url, field_values, meta, created_by, created_at, updated_at)
     VALUES (?, 'default', ?, ?, ?, ?, ?, ?, ?, '{}', NULL, ?, ?)`,
  );
  for (const s of AGENCY_SURFACES) {
    const table = TABLE(s.slug);
    let rows: Record<string, unknown>[] = [];
    try {
      rows = db.prepare(`SELECT * FROM ${table}`).all() as Record<string, unknown>[];
    } catch {
      continue; // table doesn't exist yet — skip
    }
    for (const r of rows) {
      let fv: Record<string, unknown> = {};
      try {
        fv = JSON.parse(String(r.meta || "{}"));
      } catch {
        fv = {};
      }
      const created = Number(r.created_at) || t;
      insert.run(
        String(r.id),
        s.slug,
        String(r.status || "draft"),
        String(r.category || "general"),
        String(r.title || ""),
        String(r.body || ""),
        String(r.url || ""),
        JSON.stringify(fv),
        created,
        created,
      );
    }
  }
  backfilled = true;
}

