import { ensureAgencyTables, listAgencyItems, createAgencyItem, updateAgencyItem, deleteAgencyItem, computeAgencyKpis, getAgencyItem } from "../src/lib/agency-db";

const WS = "default";
const TYPE = "app-agency";

console.log("1) List + KPIs (seeded):");
let items = listAgencyItems(TYPE, { workspaceId: WS });
console.log(`   items=${items.length}`);
console.log("   kpis=", computeAgencyKpis(TYPE, items));

console.log("\n2) Create:");
const id = createAgencyItem(TYPE, {
  workspaceId: WS,
  title: "Verify App",
  status: "design",
  category: "ios",
  field_values: { screens: 14, users: 5000, rating: 4.8 },
});
console.log("   created id=", id);
console.log("   fetched=", getAgencyItem(id)?.title);

console.log("\n3) KPIs after insert (expect screens+14, users+5000, rating avg 4.8):");
items = listAgencyItems(TYPE, { workspaceId: WS });
console.log("   kpis=", computeAgencyKpis(TYPE, items));

console.log("\n4) Update:");
updateAgencyItem(id, { title: "Verify App (edited)", status: "qa", field_values: { screens: 20 } });
const updated = getAgencyItem(id);
console.log("   title=", updated?.title, "status=", updated?.status, "screens=", (updated?.field_values as any)?.screens);

console.log("\n5) Delete:");
const ok = deleteAgencyItem(id);
console.log("   deleted=", ok, "exists after=", getAgencyItem(id) ? "yes" : "no");

console.log("\n6) Client create:");
const cid = (await import("../src/lib/agency-db")).createAgencyClient
  ? // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (require("../src/lib/agency-db") as any).createAgencyClient({ workspaceId: WS, name: "Acme Co", slug: "acme" })
  : null;
console.log("   client id=", cid);

console.log("\n✅ Data layer + KPIs + CRUD verified.");

