import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { Plus, X, Pencil, Trash2, ArrowUpRight } from "lucide-react";
import type { AgencyFieldDef } from "@/lib/agencySchema";

type Item = {
  id: string;
  agency_type: string;
  client_id: string | null;
  status: string;
  category: string;
  title: string;
  body: string;
  url: string;
  field_values: Record<string, unknown>;
  created_at: number;
};

type Schema = {
  stages: string[];
  categories: string[];
  fields: AgencyFieldDef[];
  kpis: { key: string; label: string; type: string }[];
};

const STATUS_COLOR: Record<string, string> = {
  draft: "#94a3b8", planning: "#0ea5e9", active: "#22c55e", live: "#22c55e", published: "#22c55e",
  recording: "#f59e0b", filming: "#f59e0b", editing: "#f59e0b", scripting: "#0ea5e9", sending: "#f59e0b",
  pitching: "#0ea5e9", applied: "#0ea5e9", identified: "#0ea5e9", nurturing: "#f59e0b", testing: "#f59e0b",
  design: "#6366f1", development: "#8b5cf6", qa: "#f59e0b", maintenance: "#64748b", discovery: "#0ea5e9",
