};

const emptyForm = { id: "", title: "", status: "draft", category: "general", body: "", url: "", field_values: {} as Record<string, unknown> };

export function AgencyModule({ slug, label, icon, color }: { slug: string; label: string; icon: React.ReactNode; color: string }) {
  const { data, loading, error, reload } = useFetch<{ items: Item[]; kpis: { key: string; label: string; value: number; type: string }[]; schema: Schema }>(`/api/agency/${slug}`);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [activeStage, setActiveStage] = useState<string | null>(null);

  const schema = data?.schema;
  const stages = schema?.stages || [];
  const items = data?.items || [];
  const visible = activeStage ? items.filter((i) => i.status === activeStage) : items;
  const stageCounts = stages.map((s) => ({ stage: s, n: items.filter((i) => i.status === s).length })).filter((x) => x.n > 0 || stages.length <= 8);

  const openNew = () => {
    setEditingId(null);
    setForm({ ...emptyForm, status: stages[0] || "draft", category: schema?.categories?.[0] || "general" });
    setShowForm(true);
  };
  const openEdit = (it: Item) => {
    setEditingId(it.id);
    setForm({ id: it.id, title: it.title, status: it.status, category: it.category, body: it.body, url: it.url, field_values: { ...it.field_values } });
    setShowForm(true);
  };
  const fieldVal = (key: string) => (form.field_values?.[key] ?? "") as string | number;
  const setField = (key: string, v: unknown) => setForm((f) => ({ ...f, field_values: { ...f.field_values, [key]: v } }));

  const save = async () => {
    if (!form.title) return;
    setSaving(true);
    try {
      if (editingId) {
        await fetch(`/api/agency/${slug}/${editingId}`, { method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify(form) });
      } else {
        await fetch(`/api/agency/${slug}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(form) });
      }
      setForm(emptyForm);
      setEditingId(null);
      setShowForm(false);
      reload();
    } finally {
      setSaving(false);
    }
  };
  const remove = async (id: string) => {
    if (!confirm("Delete this item?")) return;
    await fetch(`/api/agency/${slug}/${id}`, { method: "DELETE" });
    reload();
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              <span style={{ color }}>{icon}</span> {label}
            </h1>
            <p className="mt-1 text-gray-600">
              Full agency workspace — deliverables, pipeline and live KPIs.
              <span className="ml-2 inline-flex items-center gap-1 text-xs font-medium text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full border border-amber-200">
                Unified module
              </span>
            </p>
          </div>
          <button onClick={openNew} className="flex items-center gap-1.5 bg-indigo-600 text-white text-sm font-semibold px-4 py-2 rounded-lg hover:bg-indigo-700">
            <Plus className="w-4 h-4" /> New
          </button>
        </div>

        {/* KPIs */}
        {data?.kpis && data.kpis.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            {data.kpis.map((k) => (
              <div key={k.key} className="bg-white border rounded-xl p-4 shadow-sm">
                <div className="text-xs text-slate-500 uppercase tracking-wide">{k.label}</div>
                <div className="text-2xl font-black mt-1" style={{ color }}>
                  {typeof k.value === "number" ? k.value.toLocaleString() : k.value}
                  {k.type === "percent" ? "%" : k.type === "currency" ? "" : ""}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Pipeline */}
        {stages.length > 0 && (
          <div className="flex flex-wrap gap-2">
            <button onClick={() => setActiveStage(null)} className={`text-xs px-3 py-1.5 rounded-full border ${activeStage === null ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-gray-200"}`}>
              All ({items.length})
            </button>
            {stageCounts.map(({ stage, n }) => (
              <button key={stage} onClick={() => setActiveStage(stage)} className={`text-xs px-3 py-1.5 rounded-full border capitalize ${activeStage === stage ? "bg-indigo-600 text-white border-indigo-600" : "bg-white text-slate-600 border-gray-200"}`}>
                {stage} ({n})
              </button>
            ))}
          </div>
        )}

        {/* Form */}
        {showForm && (
          <div className="bg-white border rounded-xl p-5 shadow-sm space-y-3">
            <div className="flex items-center justify-between">
              <div className="text-sm font-semibold text-gray-700">{editingId ? "Edit item" : "New item"}</div>
              <button onClick={() => { setShowForm(false); setEditingId(null); setForm(emptyForm); }} className="text-gray-400 hover:text-gray-600"><X className="w-4 h-4" /></button>
            </div>
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="Title" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
            <div className="grid grid-cols-2 gap-3">
              <select className="border rounded-lg px-3 py-2 text-sm" value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })}>
                {stages.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
              <select className="border rounded-lg px-3 py-2 text-sm" value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })}>
                {(schema?.categories || []).map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            {/* Typed structured fields */}
            {schema?.fields.filter(f => !["notes", "owner", "client_ref"].includes(f.key)).map((f) => (
              <div key={f.key}>
                <label className="block text-xs text-slate-500 mb-1">{f.label}</label>
                {f.type === "select" ? (
                  <select className="w-full border rounded-lg px-3 py-2 text-sm" value={String(fieldVal(f.key))} onChange={(e) => setField(f.key, e.target.value)}>
                    <option value="">—</option>
                    {(f.options || []).map((o) => <option key={o} value={o}>{o}</option>)}
                  </select>
                ) : f.type === "textarea" ? (
                  <textarea className="w-full border rounded-lg px-3 py-2 text-sm" rows={2} value={String(fieldVal(f.key))} onChange={(e) => setField(f.key, e.target.value)} />
                ) : (
                  <input type={f.type === "number" || f.type === "currency" || f.type === "percent" ? "number" : f.type === "date" ? "date" : "text"} className="w-full border rounded-lg px-3 py-2 text-sm" value={String(fieldVal(f.key))} onChange={(e) => setField(f.key, e.target.value === "" ? "" : f.type === "number" || f.type === "currency" || f.type === "percent" ? Number(e.target.value) : e.target.value)} />
                )}
              </div>
            ))}
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="URL (optional)" value={form.url} onChange={(e) => setForm({ ...form, url: e.target.value })} />
            <textarea className="w-full border rounded-lg px-3 py-2 text-sm" rows={3} placeholder="Notes / body" value={form.body} onChange={(e) => setForm({ ...form, body: e.target.value })} />
            <button onClick={save} disabled={saving || !form.title} className="bg-indigo-600 text-white text-sm font-semibold px-4 py-2 rounded-lg disabled:opacity-50">
              {saving ? "Saving…" : editingId ? "Save changes" : "Save"}
            </button>
          </div>
        )}

        {loading && <div className="text-sm text-slate-500">Loading…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {/* Items */}
        {data && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {visible.map((it) => {
              const fv = it.field_values || {};
              const fvEntries = Object.entries(fv).filter(([, v]) => v !== "" && v !== null && v !== undefined);
              return (
                <div key={it.id} className="bg-white border rounded-xl p-4 shadow-sm flex flex-col">
                  <div className="flex items-start justify-between gap-2 mb-2">
                    <div className="font-bold text-sm text-gray-900 line-clamp-2 flex items-center gap-1">
                      {it.title}
                      {it.url && <a href={it.url} target="_blank" rel="noreferrer" className="text-indigo-500"><ArrowUpRight className="w-3.5 h-3.5" /></a>}
                    </div>
                    <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded text-white shrink-0" style={{ background: STATUS_COLOR[it.status] || "#94a3b8" }}>{it.status}</span>
                  </div>
                  <div className="text-xs text-indigo-500 mb-2 capitalize">{it.category}</div>
                  {it.body && <p className="text-xs text-slate-600 line-clamp-3 mb-2">{it.body}</p>}
                  {fvEntries.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 mb-2">
                      {fvEntries.map(([k, v]) => (
                        <span key={k} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded">
                          <span className="font-medium capitalize">{k.replace(/_/g, " ")}:</span> {typeof v === "number" ? v.toLocaleString() : String(v)}
                        </span>
                      ))}
                    </div>
                  )}
                  <div className="flex items-center gap-2 mt-auto pt-2 border-t border-gray-100">
                    <button onClick={() => openEdit(it)} className="inline-flex items-center gap-1 text-xs text-slate-500 hover:text-indigo-600"><Pencil className="w-3.5 h-3.5" /> Edit</button>
                    <button onClick={() => remove(it.id)} className="inline-flex items-center gap-1 text-xs text-slate-500 hover:text-rose-600"><Trash2 className="w-3.5 h-3.5" /> Delete</button>
                  </div>
                </div>
              );
            })}
            {visible.length === 0 && <div className="col-span-full text-center text-slate-400 py-12">No items yet. Create one above.</div>}
          </div>
        )}
      </div>
    </div>
  );
}

